// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before writing news items and sending Discord notifications.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

// RSS Input Sanitization per CLAUDE.md Prompt Injection Safeguards
// This processes external text and must sanitize before downstream use.

const feedNodes = ['RSS: CoinDesk', 'RSS: The Block', 'RSS: CoinTelegraph', 'RSS: DL News'];
const sanitizedFeeds = {};

// Instruction-like patterns to strip (per CLAUDE.md safeguards)
const INJECTION_PATTERNS = [
  /ignore\s+(previous|all|above|prior)/gi,
  /system\s*prompt/gi,
  /act\s+as/gi,
  /you\s+are\s+(now|a)/gi,
  /forget\s+(everything|all|previous)/gi,
  /override\s+(instructions|rules|previous)/gi,
  /disregard\s+(all|previous|above)/gi,
  /new\s+instructions?:/gi,
  /\[INST\]/gi,
  /\[SYSTEM\]/gi,
  /<\/?system>/gi,
  /<<SYS>>/gi
];

// URL pattern for stripping
const URL_PATTERN = /https?:\/\/[^\s)"'<>]+/gi;

// Zero-width and non-printable character pattern
const INVISIBLE_CHARS = /[\u200B-\u200F\u2028-\u202F\u2060-\u206F\uFEFF\u0000-\u001F]/g;

function sanitizeText(text) {
  if (!text || typeof text !== 'string') return '';

  let cleaned = text;

  // Remove non-printable and zero-width characters
  cleaned = cleaned.replace(INVISIBLE_CHARS, '');

  // Strip instruction-like patterns
  for (const pattern of INJECTION_PATTERNS) {
    cleaned = cleaned.replace(pattern, '[REDACTED]');
  }

  // Remove URLs from text content
  cleaned = cleaned.replace(URL_PATTERN, '');

  // Truncate to 500 chars per CLAUDE.md safeguards
  if (cleaned.length > 500) {
    cleaned = cleaned.slice(0, 500);
  }

  return cleaned.trim();
}

function shouldFlag(text) {
  if (!text || typeof text !== 'string') return false;
  const lower = text.toLowerCase();
  const flagKeywords = ['ignore', 'forget', 'override', 'system', 'prompt', 'persona'];
  return flagKeywords.some(kw => lower.includes(kw));
}

for (const nodeName of feedNodes) {
  try {
    const feed = $(nodeName).first().json;
    const items = feed?.rss?.channel?.item || feed?.items || feed?.feed?.entry || [];
    const itemList = Array.isArray(items) ? items : [items];

    sanitizedFeeds[nodeName] = itemList.map(item => {
      if (!item) return null;
      const rawTitle = item.title || '';
      const rawDesc = item.description || item.summary || item.content || '';

      return {
        title: sanitizeText(rawTitle),
        description: sanitizeText(rawDesc),
        url: item.link || item.url || item.id || '',
        pubDate: item.pubDate || item.published || item.updated || '',
        source: nodeName.replace('RSS: ', ''),
        flagged: shouldFlag(rawTitle) || shouldFlag(rawDesc)
      };
    }).filter(Boolean);
  } catch (e) {
    sanitizedFeeds[nodeName] = [];
  }
}

return [{ json: { feeds: sanitizedFeeds } }];

const keywords = [
  'bittensor', 'tao', 'sn106', 'voidai', 'void ai',
  'subnet', 'decentralized ai', 'chainlink ccip',
  'cross-chain bridge', 'dtao', 'opentensor'
];

const sanitizedFeeds = $input.first().json.feeds;
const allItems = [];

for (const [nodeName, items] of Object.entries(sanitizedFeeds)) {
  for (const item of items) {
    if (!item) continue;

    // Skip flagged items (possible injection)
    if (item.flagged) continue;

    const title = (item.title || '').toLowerCase();
    const desc = (item.description || '').toLowerCase();
    const combined = title + ' ' + desc;

    const isRelevant = keywords.some(kw => combined.includes(kw));
    if (isRelevant) {
      allItems.push({
        title: item.title || 'Untitled',
        description: item.description || '',
        url: item.url || '',
        published: item.pubDate || '',
        source: item.source || nodeName.replace('RSS: ', ''),
        type: 'news'
      });
    }
  }
}

// Deduplicate by URL within this batch
const seen = new Set();
const unique = allItems.filter(item => {
  if (!item.url || seen.has(item.url)) return false;
  seen.add(item.url);
  return true;
});

// Check against already-processed items using static data (n8n Cloud compatible)
const staticData = $getWorkflowStaticData('global');
if (!staticData.processed_urls) {
  staticData.processed_urls = [];
}

const newItems = unique.filter(item => !staticData.processed_urls.includes(item.url));

// Update processed URLs, keep last 1000
staticData.processed_urls = [...staticData.processed_urls, ...newItems.map(i => i.url)].slice(-1000);

if (newItems.length === 0) {
  return [{ json: { no_new_items: true, scanned: unique.length } }];
}

return newItems.map(item => ({ json: item }));

