// Write filtered news items to static data as raw items for manual content generation.
// No Claude API dependency. Content generation happens via Claude Code skills.

const items = $input.all();
const staticData = $getWorkflowStaticData('global');

if (!staticData.news_items) {
  staticData.news_items = {};
}

const collectedAt = new Date().toISOString();
const writtenItems = [];

for (const inputItem of items) {
  const item = inputItem.json;
  const slug = (item.title || 'untitled').toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 50);
  const date = new Date().toISOString().split('T')[0];
  const itemKey = `news-${date}-${slug}`;

  const newsItem = {
    type: 'news-item',
    status: 'pending_content_generation',
    collected_at: collectedAt,
    source: item.source || 'Unknown',
    title: item.title || 'Untitled',
    summary: (item.description || '').slice(0, 500),
    original_url: item.url || '',
    content_brief: 'Generate a tweet from this news item using /generate-tweet'
  };

  staticData.news_items[itemKey] = newsItem;
  writtenItems.push({ key: itemKey, title: newsItem.title, source: newsItem.source });
}

// Clean up old news items (keep last 50)
const itemKeys = Object.keys(staticData.news_items).sort();
if (itemKeys.length > 50) {
  for (const oldKey of itemKeys.slice(0, itemKeys.length - 50)) {
    delete staticData.news_items[oldKey];
  }
}

return [{ json: { count: writtenItems.length, items: writtenItems } }];

